SELECT ?athlete ?label WHERE {
  ?event wdt:P31 wd:Q36103.
  ?athlete wdt:P1538 ?event.
  ?athlete wdt:P9140 ?time.
  OPTIONAL { ?athlete rdfs:label ?label. FILTER (lang(?label) = "en"). }
} ORDER BY DESC(?time) LIMIT 1

